                  "Polynesian Village": { handle: "@polynesianresort", type: "Hotels", rating: 91, posts: 876, followers: "31.4k", network: "2.1k", img: "https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=400&q=80", desc: "Tropical-themed resort on the shores of Seven Seas Lagoon with stunning views of Magic Kingdom.", networkRecs: [3], hasMoments: true },
                  "TRON Lightcycle": { handle: "@tronlightcycle", type: "Rides", rating: 89, posts: 189, followers: "42.7k", network: "3.8k", img: "https://images.unsplash.com/photo-1536086845584-8cdb6c2e0e14?w=400&q=80", desc: "Race your lightcycle through the digital frontier in this thrilling high-speed coaster at Magic Kingdom.", networkRecs: [2, 3], hasMoments: true },
