                                  <div style={{ background: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)", borderRadius: 100, padding: "3px 8px", fontSize: 11, fontWeight: 600, color: "#FFF" }}>{post.videoDuration}</div>
