                  const qr = PRODUCT_QUICK_RATES[product.id] || { up: [], down: [] };
                  const myRate = quickRates[product.id] || null;
                  const reviewUpCount = reviewPosts.filter(r => r.vote === "up").length;
                  const reviewDownCount = reviewPosts.filter(r => r.vote === "down").length;
                  const totalUp = qr.up.length + reviewUpCount + (myRate === "up" ? 1 : 0);
                  const totalDown = qr.down.length + reviewDownCount + (myRate === "down" ? 1 : 0);
                  const totalRatings = totalUp + totalDown;
