                          <svg width="18" height="18" viewBox="0 0 24 24" fill={myRate === "up" ? A.brand : "none"} stroke={myRate === "up" ? A.brand : A.foggy} strokeWidth="1.5"><path d="M14 9V5a3 3 0 0 0-3-3l-4 9v11h11.28a2 2 0 0 0 2-1.7l1.38-9a2 2 0 0 0-2-2.3H14z" /><path d="M7 22H4a2 2 0 0 1-2-2v-7a2 2 0 0 1 2-2h3" /></svg>
