                            <button onClick={() => { if (editNameDraft.trim() && editNameDraft.trim() !== editName) { setNameAtLastChange(editName); setEditName(editNameDraft.trim()); setNameLastChanged(Date.now()); } setActiveEditField(null); }} style={{ all: "unset", cursor: editNameDraft.trim() ? "pointer" : "default", marginTop: 16, padding: "10px 0", width: "100%", borderRadius: 100, background: editNameDraft.trim() ? A.brand : A.border, textAlign: "center", boxSizing: "border-box", fontSize: 14, fontWeight: 700, color: "#FFF", fontFamily: F }}>Done</button>
