                  <svg width="22" height="22" viewBox="0 0 24 24" fill={newPostFlash ? "#FFD700" : "none"} stroke={newPostFlash ? "#FFD700" : "#FFF"} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2" /></svg>
